#include <unordered_map>

struct Vec2 {
    float x, y;
    bool operator==(const Vec2& o) const { return x == o.x && y == o.y; }
};

// ❌ خطأ ترجمة: Vec2 لا يملك std::hash
// std::unordered_map<Vec2, int> grid;

// ✅ الحل: تخصيص std::hash للنوع
namespace std {
template<>
struct hash<Vec2> {
    size_t operator()(const Vec2& v) const noexcept {
        auto hx = std::hash<float>{}(v.x);
        auto hy = std::hash<float>{}(v.y);
        return hx ^ (hy << 1); // دمج بسيط
    }
};
}

